import { ChangeDetectorRef, Component, Inject, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Invoice } from '../../models/invoice';
import { InvoiceService } from '../../services/invoice.service';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { InvoiceStatusPipe } from '../../pipes/invoice-status.pipe'
import { InvoiceCustomerPipe } from '../../pipes/invoice-customer.pipe'

@Component({
  selector: 'invoice-list',
  imports: [CommonModule, RouterLink, InvoiceStatusPipe, InvoiceCustomerPipe],
  templateUrl: './invoice-list.component.html',
  styleUrls: ['./invoice-list.component.css'],
  standalone: true
})
export class InvoiceListComponent implements OnInit{
  public invoices: Invoice[] = [];

  private invoiceStatuses: { [statusId: number]: string; } = {};

  constructor(
    http: HttpClient,
    @Inject('BASE_URL') baseUrl: string,
    private readonly invoiceService: InvoiceService,
    private readonly changeDetectorRef: ChangeDetectorRef,
    private readonly router: Router
  ) {

    const invoicesEndPoint = baseUrl + 'api/invoice/all';
    console.log("End point :" + invoicesEndPoint);    
  }

  ngOnInit(): void {
    this.loadInvoiceStatuses();
    this.loadTransactions();
  }

  loadInvoiceStatuses() {
    this.invoiceStatuses[0] = "UnPaid";
    this.invoiceStatuses[1] = "Partially Paid";
    this.invoiceStatuses[2] = "Paid";
    this.invoiceStatuses[3] = "Over Due";
  }

  loadTransactions() {
    this.invoiceService.getAll()
      .subscribe((data) => {

        this.invoices = data;
        console.log('list...items:' + this.invoices.length);

        this.changeDetectorRef.detectChanges();
      });
  }

  viewDetails(id: number) {
    this.router.navigate(['/invoice-form/' + id])
  }

  AddNew() {    
    this.router.navigate(['/invoice-form'])
  }

  incomeSummary(): number {
    return 0;
  }

  expenseSummary(): number {
    return 0;
  }

  filterBy(filterBy: string) {
    console.log("filering by :" + filterBy);
  }



}
<div class="row mb-4 g-4">
  <div class="col-md-4 ">
    <div (click)="filterBy('income')" class="card h-100 bg-success bg-opacity-75 text-white">
      <div class="card-body">
        <h5 class="card-title">Income</h5>
        <h3 class="card-title">{{incomeSummary() | currency:'R'}}</h3>
      </div>
    </div>
  </div>
  <div class="col-md-4 ">
    <div (click)="filterBy('expense')" class="card h-100 bg-danger bg-opacity-75 text-white">
      <div class="card-body">
        <h5 class="card-title">Expenses</h5>
        <h3 class="card-title">{{expenseSummary() | currency:'R'}}</h3>
      </div>
    </div>
  </div>
</div>

<h1 id="tableLabel">Invoices</h1>

<p *ngIf="!invoices?.length"><em>Loading...</em></p>

<div class="ms-auto">
  <a class="btn btn-outline-dark me-2"
     (click)="AddNew()">
    <li class="bi bi-plus-circle"> Add New</li>
  </a>

  <div id="filter-caption" style="display:none">Filtered by</div>
</div>

<table class="table table-striped py-2 table-hover align-middle" *ngIf="invoices.length">
  <thead>
    <tr>
      <th scope="col">Id</th>
      <th scope="col">Customer</th>
      <th scope="col">InvoiceDate</th>

      <th scope="col">DueDate</th>
      <th scope="col">InvoiceAmount</th>
      <th scope="col">PaidAmount</th>
      <th scope="col">Balance</th>
      <th scope="col">Status</th>
    </tr>
  </thead>
  <tbody>
    <tr *ngFor="let inv of invoices"
        class="trans-row"
        (click)="viewDetails(inv.invoiceNumber)">
      <td>{{ inv.invoiceNumber }}</td>
      <td>{{ inv.customerId | invoiceCustomerPipe }}</td>
      <td>{{ inv.invoiceDate }}</td>

      <td>{{ inv.dueDate }}</td>
      <td>{{ inv.invoiceAmount }}</td>
      <td>{{ inv.paidAmount }}</td>
      <td>{{ inv.balance }}</td>
      <td>{{ inv.statusId | invoiceStatusPipe }}</td>
    </tr>
  </tbody>
</table>
